  1	import * as React from 'react';
  2	import { Button, Form, FormGroup, Modal, ModalVariant, TooltipPosition } from '@patternfly/react-core';
  3	import { UserSettingsActions } from '../../actions/UserSettingsActions';
  4	import { HistoryManager, location, URLParam } from '../../app/History';
  5	import { useKialiDispatch, useKialiSelector } from '../../hooks/redux';
  6	import { DurationInSeconds, IntervalInMilliseconds, TimeRange } from '../../types/Common';
  7	import { DurationDropdownComponent } from '../Dropdown/DurationDropdown';
  8	import { RefreshComponent } from '../Refresh/Refresh';
  9	import { TimeRangeComp } from './TimeRangeComponent';
 10	import { kioskDurationAction, kioskTimeRangeAction } from '../Kiosk/KioskActions';
 11	import { useKialiTranslation } from 'utils/I18nUtils';
 12	import { toValidDuration } from '../../config/ServerConfig';
 13	import { config } from '../../config';
 14	
 15	interface Props {
 16	  customDuration: boolean;
 17	  isOpen: boolean;
 18	
 19	  onCancel?: () => void;
 20	  onConfirm?: () => void;
 21	}
 22	
 23	export const TimeDurationModal: React.FC<Props> = (props: Props) => {
 24	  const dispatch = useKialiDispatch();
 25	  const { t, i18n } = useKialiTranslation();
 26	
 27	  const reduxDuration = useKialiSelector(state => state.userSettings.duration);
 28	  const reduxRefreshInterval = useKialiSelector(state => state.userSettings.refreshInterval);
 29	  const reduxTimeRange = useKialiSelector(state => state.userSettings.timeRange);
 30	
 31	  const [duration, setDuration] = React.useState<number>(0);
 32	  const [refreshInterval, setRefreshInterval] = React.useState<number>(0);
 33	  const [timeRange, setTimeRange] = React.useState<TimeRange>({});
 34	
 35	  React.useEffect(() => {
 36	    const urlParams = new URLSearchParams(location.getSearch());
 37	    const urlDuration = HistoryManager.getDuration(urlParams);
 38	    const urlRefresh = HistoryManager.getNumericParam(URLParam.REFRESH_INTERVAL, urlParams);
 39	    const urlTimeRange = HistoryManager.getNumericParam(URLParam.RANGE_DURATION, urlParams);
 40	    const urlFrom = HistoryManager.getNumericParam(URLParam.FROM, urlParams);
 41	    const urlTo = HistoryManager.getNumericParam(URLParam.TO, urlParams);
 42	
 43	    const getInitDuration = (): number => {
 44	      if (!props.customDuration && urlDuration) {
 45	        return toValidDuration(urlDuration);
 46	      }
 47	      return reduxDuration;
 48	    };
 49	
 50	    const getInitRefresh = (): number => {
 51	      if (urlRefresh) {
 52	        // Validate value
 53	        if (urlRefresh === 0 || config.toolbar.refreshInterval[urlRefresh]) {
 54	          return urlRefresh;
 55	        }
 56	      }
 57	      return reduxRefreshInterval;
 58	    };
 59	
 60	    const getUrlTimeRange = (): TimeRange => ({
 61	      ...(urlTimeRange != null && { rangeDuration: urlTimeRange }),
 62	      ...(urlFrom != null && { from: urlFrom }),
 63	      ...(urlTo != null && { to: urlTo })
 64	    });
 65	
 66	    const getInitTimeRange = (): TimeRange => {
 67	      const tm = getUrlTimeRange();
 68	
 69	      if (!tm.rangeDuration && !tm.from && !tm.to && props.customDuration) {
 70	        return reduxTimeRange;
 71	      }
 72	
 73	      return tm;
 74	    };
 75	
 76	    setDuration(getInitDuration());
 77	    setRefreshInterval(getInitRefresh());
 78	    setTimeRange(getInitTimeRange());
 79	
 80	    if (urlDuration !== undefined) {
 81	      dispatch(UserSettingsActions.setDuration(urlDuration));
 82	    }
 83	
 84	    // Update just when valid
 85	    if (urlRefresh !== undefined && (urlRefresh === 0 || config.toolbar.refreshInterval[urlRefresh])) {
 86	      dispatch(UserSettingsActions.setRefreshInterval(urlRefresh));
 87	    }
 88	
 89	    if (getUrlTimeRange() !== undefined) {
 90	      dispatch(UserSettingsActions.setTimeRange(getUrlTimeRange()));
 91	    }
 92	    // eslint-disable-next-line react-hooks/exhaustive-deps
 93	  }, []);
 94	
 95	  const handleCancel = (): void => {
 96	    // reset the dialog
 97	    setDuration(reduxDuration);
 98	    setRefreshInterval(reduxRefreshInterval);
 99	    setTimeRange(reduxTimeRange);
100	    HistoryManager.setParam(URLParam.REFRESH_INTERVAL, String(reduxRefreshInterval));
101	
102	    if (props.onCancel) {
103	      props.onCancel();
104	    }
105	  };
106	
107	  const handleConfirm = (): void => {
108	    dispatch(UserSettingsActions.setRefreshInterval(refreshInterval));
109	    HistoryManager.setParam(URLParam.REFRESH_INTERVAL, String(refreshInterval));
110	
111	    if (!props.customDuration) {
112	      dispatch(UserSettingsActions.setDuration(duration));
113	      HistoryManager.setParam(URLParam.DURATION, String(duration));
114	      kioskDurationAction(duration);
115	    } else {
116	      timeRange.rangeDuration
117	        ? HistoryManager.setParam(URLParam.RANGE_DURATION, String(timeRange.rangeDuration))
118	        : HistoryManager.deleteParam(URLParam.RANGE_DURATION);
119	      timeRange.from
120	        ? HistoryManager.setParam(URLParam.FROM, String(timeRange.from))
121	        : HistoryManager.deleteParam(URLParam.FROM);
122	      timeRange.to
123	        ? HistoryManager.setParam(URLParam.TO, String(timeRange.to))
124	        : HistoryManager.deleteParam(URLParam.TO);
125	
126	      dispatch(UserSettingsActions.setTimeRange(timeRange));
127	      kioskTimeRangeAction(timeRange);
128	    }
129	
130	    if (props.onConfirm) {
131	      props.onConfirm();
132	    }
133	  };
134	
135	  const handleSetDuration = (d: DurationInSeconds): void => {
136	    setDuration(d);
137	  };
138	
139	  const handleSetRefreshInterval = (r: IntervalInMilliseconds): void => {
140	    setRefreshInterval(r);
141	  };
142	
143	  const handleSetTimeRange = (r: TimeRange): void => {
144	    setTimeRange(r);
145	  };
146	
147	  return (
148	    <Modal
149	      id="time-duration-modal"
150	      aria-label={t('Time duration')}
151	      variant={ModalVariant.small}
152	      width={700}
153	      isOpen={props.isOpen}
154	      showClose={false}
155	      actions={[
156	        <Button key="confirm" variant="primary" onClick={handleConfirm}>
157	          {t('Confirm')}
158	        </Button>,
159	
160	        <Button key="cancel" variant="link" onClick={handleCancel}>
161	          {t('Cancel')}
162	        </Button>
163	      ]}
164	      position="top"
165	    >
166	      <Form isHorizontal={true}>
167	        {props.customDuration ? (
168	          <FormGroup label={t('Time range')} fieldId="drform-time-range">
169	            <div style={{ display: 'flex' }}>
170	              <TimeRangeComp timeRange={timeRange} setTimeRange={handleSetTimeRange} tooltip={t('Time range')} />
171	            </div>
172	          </FormGroup>
173	        ) : (
174	          <FormGroup label={t('Duration')} fieldId="drform-duration">
175	            <DurationDropdownComponent
176	              id={'drform-duration-dd'}
177	              disabled={false}
178	              duration={duration}
179	              prefix={t('Last')}
180	              setDuration={handleSetDuration}
181	              tooltip={t('Traffic metrics per refresh')}
182	              tooltipPosition={TooltipPosition.top}
183	            />
184	          </FormGroup>
185	        )}
186	
187	        <FormGroup label={t('Refresh interval')} fieldId="drform-refresh">
188	          <RefreshComponent
189	            id="drform-metrics-refresh"
190	            hideRefreshButton={true}
191	            language={i18n.language}
192	            refreshInterval={refreshInterval}
193	            setRefreshInterval={handleSetRefreshInterval}
194	          />
195	        </FormGroup>
196	      </Form>
197	    </Modal>
198	  );
199	};

